pub fn tilde_expand(input: &str) -> Option<String> {
    if let Some(rest) = input.strip_prefix("~/") {
        let home = std::env::var("HOME").ok()?;
        return Some(format!("{home}/{rest}"));
    }
    if input == "~" {
        return std::env::var("HOME").ok();
    }
    Some(input.to_string())
}

